mapper.update:
UPDATE festival_review
SET
    is_deleted = 'Y',
    updated_at = SYSDATE
WHERE review_id = #{review_id}
  AND member_id = #{member_id}

mapper.select:
SELECT COUNT(*)
FROM review_report
WHERE review_id = #{review_id}
  AND member_id = #{member_id}

mapper.update:
UPDATE festival_review
SET report_count = NVL(report_count, 0) + 1
WHERE review_id = #{review_id}
